<template>
  <view class="draggable-container">
    <view 
      v-for="(item, index) in list" 
      :key="item.id || index"
      class="draggable-item"
      :class="{ 'dragging': index === draggingIndex }"
      :style="{ 'transition': isDragging ? 'none' : 'all 0.3s ease' }"
      @touchstart="handleTouchStart($event, index)"
      @touchmove="handleTouchMove($event, index)"
      @touchend="handleTouchEnd($event, index)"
      @touchcancel="handleTouchEnd($event, index)"
    >
      <slot :item="item" :index="index"></slot>
    </view>
  </view>
</template>

<script setup>
import { ref, watch, computed } from 'vue';

// 组件属性
const props = defineProps({
  modelValue: {
    type: Array,
    required: true
  },
  animation: {
    type: Boolean,
    default: false
  },
  ghostClass: {
    type: String,
    default: 'ghost'
  }
});

// 组件事件
const emit = defineEmits(['update:modelValue', 'start', 'end']);

// 内部状态
const list = ref([...props.modelValue]);
const isDragging = ref(false);
const draggingIndex = ref(-1);
const startY = ref(0);
const startIndex = ref(-1);
const currentY = ref(0);

// 监听 modelValue 变化，更新内部列表
watch(
  () => props.modelValue,
  (newValue) => {
    list.value = [...newValue];
  },
  { deep: true }
);

// 触摸开始事件
const handleTouchStart = (event, index) => {
  isDragging.value = true;
  draggingIndex.value = index;
  startIndex.value = index;
  startY.value = event.touches[0].clientY;
  
  // 触发 start 事件
  emit('start', { index });
};

// 触摸移动事件
const handleTouchMove = (event, index) => {
  if (!isDragging.value || index !== draggingIndex.value) return;
  
  currentY.value = event.touches[0].clientY;
  
  // 计算移动距离对应的项目索引
  const moveDistance = currentY.value - startY.value;
  const itemHeight = 140; // 假设每个项目高度为 140rpx
  const moveItems = Math.round(moveDistance / (itemHeight * 0.8)); // 0.8 是容差系数
  
  if (moveItems !== 0) {
    const newIndex = startIndex.value + moveItems;
    
    // 确保索引在有效范围内
    if (newIndex >= 0 && newIndex < list.value.length) {
      // 更新列表顺序
      const newList = [...list.value];
      const [removed] = newList.splice(startIndex.value, 1);
      newList.splice(newIndex, 0, removed);
      
      // 更新内部状态
      list.value = newList;
      startIndex.value = newIndex;
      startY.value = currentY.value;
      
      // 更新 modelValue
      emit('update:modelValue', newList);
    }
  }
};

// 触摸结束事件
const handleTouchEnd = (event, index) => {
  if (!isDragging.value) return;
  
  // 触发 end 事件
  emit('end', { index: startIndex.value });
  
  // 重置状态
  isDragging.value = false;
  draggingIndex.value = -1;
  startIndex.value = -1;
  startY.value = 0;
  currentY.value = 0;
};
</script>

<style scoped>
.draggable-container {
  position: relative;
}

.draggable-item {
  position: relative;
  transition: all 0.3s ease;
}

.dragging {
  z-index: 999;
  opacity: 0.8;
  transform: scale(1.02);
  box-shadow: 0 4rpx 12rpx rgba(0, 0, 0, 0.15);
}

/* 默认的 ghost 样式 */
.ghost {
  opacity: 0.5;
  background-color: #f5f5f5;
}
</style>